# scripts/upgrade/plan-window.py
"""Generates the upgrade window plan from the dependency inventory and upgrade targets."""
from dataclasses import dataclass
from datetime import datetime, timedelta
from typing import Literal

UpgradeRisk = Literal["low", "medium", "high"]

@dataclass
class DependencyUpgrade:
    package: str
    from_version: str
    to_version: str
    risk: UpgradeRisk
    is_llm_related: bool
    is_vector_db: bool
    eval_suite_required: bool
    estimated_test_minutes: int
    rollback_artifact: str

@dataclass
class UpgradeWindowPlan:
    window_date: datetime
    window_duration_hours: float
    upgrades: list[DependencyUpgrade]
    total_test_minutes: int
    rollback_soak_hours: int = 24

    def has_high_risk(self) -> bool:
        return any(u.risk == "high" for u in self.upgrades)

    def requires_eval_suite(self) -> bool:
        return any(u.eval_suite_required for u in self.upgrades)

    def estimated_rollback_time_minutes(self) -> int:
        # Base rollback is 20 min; add 15 min if eval suite needed for verification
        return 20 + (15 if self.requires_eval_suite() else 0)

    def summary(self) -> str:
        high = [u.package for u in self.upgrades if u.risk == "high"]
        return (
            f"Upgrade window: {self.window_date.strftime('%Y-%m-%d %H:%M')} UTC\n"
            f"Duration: {self.window_duration_hours}h\n"
            f"Upgrades: {len(self.upgrades)} packages ({len(high)} high-risk: {high})\n"
            f"Eval suite required: {self.requires_eval_suite()}\n"
            f"Rollback soak: {self.rollback_soak_hours}h\n"
            f"Rollback time: ~{self.estimated_rollback_time_minutes()} min"
        )
